scwin.f_Set = function (gubun) {
  switch (gubun) {
    case "INIT":
      //초기화
      if (scwin.tabNo == "0") {
        // tab1    		
        statusFlag = "I";
      } else if (scwin.tabNo == "1") {
        // tab2  
        statusFlag = "I";
      }
      break;
    case "RETRIEVE":
      //조회모드	
      if (scwin.tabNo == "0") {
        // tab1   			            	
        statusFlag = ""; // flag null 
      } else if (scwin.tabNo == "1") {
        // tab2          	
        statusFlag = ""; // flag null 			
      }
      break;
    case "SAVE":
      if (scwin.tabNo == "0") {
        // tab1   	        	
        scwin.f_Set("RETRIEVE");
      } else if (scwin.tabNo == "1") {
        // tab2
        scwin.f_Set("RETRIEVE");
      }
      break;
  }
};

