scwin.f_houseBlLoadingBiz = function (Row) {
  var param1 = "";
  var param2 = "";
  var param3 = "";
  var param4 = "";
  var param5 = "";
  var param6 = "";
  var param7 = "";
  var param8 = "";
  var param9 = "";
  var param10 = "";
  var param11 = "";
  var param12 = "";
  var param13 = "";
  var param14 = "";
  param1 = acb_cnd_lc_seaAir.getValue();
  param2 = acb_cnd_lc_iogb.getValue();
  param3 = ed_cnd_ed_resultDtFrom.getValue();
  param4 = ed_cnd_ed_resultDtTo.getValue();
  if (acb_cnd_lc_kindTab1.getValue() == "1") {
    // customer
    param5 = ds_performanceBiz.getCellData(Row, "vcol02");
  } else {
    param5 = ds_performanceBiz.getCellData(Row, "vcol04");
  }
  param6 = ed_cnd_ed_loadCd.getValue();
  param7 = ed_cnd_txt_loadNm.getValue();
  param8 = ed_cnd_ed_cntyCd.getValue();
  param9 = ed_cnd_txt_cntyNm.getValue();
  param10 = ed_cnd_ed_itemCd.getValue();
  param11 = ed_cnd_txt_itemNm.getValue();
  if (acb_cnd_lc_kindTab1.getValue() == "1") {
    // dept						
    param12 = ds_performanceBiz.getCellData(Row, "vcol04");
  } else {
    param12 = ds_performanceBiz.getCellData(Row, "vcol02");
  }
  param13 = ed_cnd_ed_arCd.getValue();
  param14 = ed_cnd_txt_arNm.getValue();
  const strParam = {
    sysCd: "PerformanceEBC" // 시스템코드
    ,

    queryId: "retriveHouseBlList" // 쿼리ID
    ,

    param1: param1,
    param2: param2,
    param3: param3,
    param4: param4,
    param5: param5,
    param6: param6,
    param7: param7,
    param8: param8,
    param9: param9,
    param10: param10,
    param11: param11,
    param12: param12,
    param13: param13,
    param14: param14
  };
  //데이터셋에 정보설정
  dma_commonPopup.setEmptyValue();
  dma_commonPopup.setJSON(strParam);
  $c.sbm.execute($p, sbm_houseBlBiz);
};
scwin.sbm_houseBlBiz_submitdone = function (e) {
  // 조회 성공시
  //.log("[sbm_houseBlBiz_submitdone] >>> e.responseJSON.resultDataSet[0].Code = " + e.responseJSON.resultDataSet[0].Code)
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    // 데이타셋 설정
    ds_houseBlBiz.setJSON(e.responseJSON.GAUCE);
  }
};

