/**
 * 가우스의 decode 기능을 대체하는 공통 함수
 * @param {String} val - 원본 데이터
 * @param {Array} args - [key1, value1, key2, value2, ..., default]
 */
scwin.fn_girdDecode = function (val, args) {
  var value = (val || "").trim();
  for (var i = 0; i < args.length - 1; i += 2) {
    if (value === args[i]) {
      return args[i + 1];
    }
  }
  // 매칭되는 값이 없을 경우 마지막 인자(Default) 반환
  return args[args.length - 1];
};

// SEA/AIR 포맷터 (vcol01)
scwin.fmt_vcol01 = function (value) {
  // decode(vcol01, 'S','Sea', 'A','Air', '', '', '계 ','계 ', '합계 ','합계 ')
  return scwin.fn_girdDecode(value, ["S", "Sea", "A", "Air", "", "", "계", "계", "합계"]);
};

// IN/OUT 포맷터 (vcol02)
scwin.fmt_vcol02 = function (value) {
  // decode(vcol02, 'I','Import', 'O','Export', '', '', '계 ','계 ', '합계 ','합계 ')
  return scwin.fn_girdDecode(value, ["I", "Import", "O", "Export", "", "", "계", "계", "합계"]);
};
